<template>
    <view>
        <view class="container">
            <view class="memCount">
                <view class="mem1">
                    メンバー数
                </view>
                <view class="mem2">
                    <text>280</text>/300
                </view>
            </view>
            <view class="appointSet">
                <view>予約配信</view>
                <u-switch v-model="value" activeColor="#34C759"></u-switch>
            </view>
            <view class="date">
                <view class="fu">オフにすると、すぐにメッセージが配信されます</view>
                <view class="can">
                    <view class="canLeft">
                        <u-icon top="5" color="#aaa" name="calendar" size="34"></u-icon>
                    </view>
                    <view style="box-sizing: border-box;padding: 0 20upx;" @click="chooseDate">
                        {{todayDate}}({{toweek}}) <text style="margin-left: 20upx;"
                            @click.stop="chooseTime">{{nowTime}}</text>
                    </view>
                </view>
            </view>
            <view class="title">
                配信ターゲット
            </view>
            <view class="chooseItem">
                <view class="item">
                    <view class="itemLeft">
                        <view class="unselect" @click="changeTab(0)" v-if="current == 1"></view>
                        <view class="selected" v-if="current == 0">
                            <view class="fill"></view>
                        </view>
                    </view>
                    <view class="itemRight" :style="current == 0? 'color:#1D1D1F;' : 'color: #AAAAAA' ">
                        すべて
                    </view>
                </view>
                <view class="item">
                    <view class="itemLeft">
                        <view class="unselect" @click="changeTab(1)" v-if="current == 0"></view>
                        <view class="selected" v-if="current == 1">
                            <view class="fill"></view>
                        </view>
                    </view>
                    <view class="itemRight" :style="current == 1? 'color:#1D1D1F;' : 'color: #AAAAAA' ">
                        絞り込み
                    </view>
                </view>
            </view>
            <view class="content" v-if="current == 1">
                <view class="contentItem" v-for="(item,index) in tabs" @click="toSceen(index)">
                    <view class="tabLeft">
                        <view class="tabTop" v-text="item.name"></view>
                        <view class="tabBot" v-text="item.title"></view>
                    </view>
                    <view class="tabRight">
                        <image src="../../../../static/icons/right.png" mode=""></image>
                    </view>
                </view>
            </view>
            <u-button type="success" color="#34C759" class="btn" @click="show6 = true">メッセージを配信</u-button>
            <view class="blank"></view>
        </view>
        <u-calendar confirmText="完了" :show="show" :closeOnClickOverlay='true' monthNum="36" :showTitle="false"
            @close="closeDate" @confirm="confirmDate"></u-calendar>
        <u-datetime-picker @confirm="timeconfirm" :show="show1" :closeOnClickOverlay="true" v-model="value1" mode="time"
            @close="closeTime">
        </u-datetime-picker>
        <mod v-if="showModule" @getStatus="getStatus" :config="configs"></mod>
        <confirms :dates="todayDate" v-if="show6 == true" :number="num" @confirm="saveData" @cancel="show6 = false"></confirms>
        <pays :dates="todayDate" v-if="show7 == true" :number="num" @confirm="goPay" @cancel="show7 = false"></pays>
    </view>
</template>

<script>
    import mod from "../../../../components/mod.vue"
    import confirms from "@/components/alerts/pe1/pe1.vue"
    import pays from "@/components/alerts/pe2/pe2.vue"
    import {
        addNewTiming,
        editTiming,
        getExtra,
        payExtra
    } from "@/api/index.js"
    export default {
        components: {
            mod,
            confirms,
            pays
        },
        data() {
            return {
                current: 0,
                value: true,
                show1: false,
                show2: false,
                show6: false,
                shows:false,
                show7: true,
                value1: "",
                show: false,
                showModule: false,
                todayDate: '',
                nowTime: "",
                toweek: "",
                num:102,
                query: {},
                configs: {
                    title: 'この情報を削除しますか？',
                    content: '削除すると、この情報は完全に削除されます。',
                    confirm: true,
                    cancel: true,
                    confirmText: "情報を削除",
                    cancelText: "キャンセル",
                    type: 'button'
                },
                tabs: [{
                        name: "誕生月",
                        title: "誕生月を設定"
                    },
                    {
                        name: "性別",
                        title: "性別を設定"
                    },
                    {
                        name: "来店期間",
                        title: "来店期間を設定"
                    },
                    {
                        name: "来店回数",
                        title: "来店回数を設定"
                    }
                ]
            }
        },
        created() {
            
        },
        onLoad(options) {
           let that = this
           let timing = uni.getStorageSync("timing")
           let query = options
           that.query = query
           if (query.source == "edit") {
               that.current = timing.receiver * 1 - 1
               let fullTime = timing.order_time.split(" ")
               console.log(fullTime)
               that.todayDate = fullTime[0]
               that.nowTime = fullTime[1]
               that.getWeek(fullTime[0])
               that.value = timing.is_order == 1 ? true : false
           } else if (query.source == "add") {
               this.getToday()
           } 
        },
        methods: {
            goPay(){
              let that = this
              let data = {}
              data['type'] = 1
              getExtra(data).then((res) => {
                  console.log(res)
                  if(res.code == 200){
                      let tem = {}
                      tem.order_no = res.data.order_no 
                      payExtra(tem).then((result) => {
                          if(result.code == 200 && result.data.url != ''){
                              setTimeout(function() {
                                  uni.navigateTo({
                                      url:"../../../webview/webview?link="+res.data.url
                                  })
                              }, 500)
                          }else{
                              uni.showToast({
                                  title:result.message,
                                  icon: "none",
                                  duration:1500
                              })
                              that.show1 = false
                              that.show2 = false
                              // setTimeout(function() {
                              //     uni.switchTab({
                              //         url:"../../index/index"
                              //     })
                              // }, 1500)
                          }
                      })
                  }else{
                      uni.showToast({
                          title:res.message,
                          icon:"none"
                      })
                  }
              })
            },
            toSceen(e) {
                console.log(e)
                if (e == 0) {
                    uni.navigateTo({
                        url: "birthday/birthday"
                    })
                } else if (e == 1) {
                    uni.navigateTo({
                        url: "sex/sex"
                    })
                } else if (e == 2) {
                    uni.navigateTo({
                        url: "time/time"
                    })
                } else {
                    uni.navigateTo({
                        url: "times/times"
                    })
                }
            },
            changeTab(e) {
                this.current = e
            },
            chooseDate(e) {
                this.show = true
            },
            closeDate() {
                this.show = false
            },
            chooseTime() {
                this.show1 = true
            },
            closeTime() {
                this.show1 = false
            },
            getStatus(e) {
                console.log(e)
            },
            timeconfirm(e) {
                this.show1 = false
                this.nowTime = e.value
            },
            getToday() {
                let that = this
                let date = new Date()
                let year = date.getFullYear()
                let month = date.getMonth() + 1 < 10 ? '0' + (date.getMonth() + 1) : date.getMonth() + 1
                let day = date.getDate() < 10 ? '0' + date.getDate() : date.getDate()
                let week = date.getDay() == 0 ? '日' : date.getDay() == 1 ? '月' : date.getDay() == 2 ? "火" : date
                    .getDay() == 3 ? "水" : date.getDay() == 4 ? "木" : date.getDay() == 5 ? '金' : '土'
                let hour = date.getHours() < 10 ? "0" + date.getHours() : date.getHours()
                let minutes = date.getMinutes() < 10 ? '0' + date.getMinutes() : date.getMinutes()
                let final = year + "-" + month + "-" + day
                that.toweek = week
                that.todayDate = final
                that.nowTime = hour + ":" + minutes
            },
            getWeek(e) {
                let that = this
                let date = new Date(e)
                console.log("date", date.getDay())
                let week = date.getDay() == 0 ? '日' : date.getDay() == 1 ? '月' : date.getDay() == 2 ? "火" : date
                    .getDay() == 3 ? "水" : date.getDay() == 4 ? "木" : date.getDay() == 5 ? '金' : '土'
                that.toweek = week
                that.todayDate = e
            },
            confirmDate(e) {
                console.log(e)
                this.show = false
                this.getWeek(e[0])
            },
            saveData() {
                let that = this
                let data = uni.getStorageSync("timing")
                data.is_order = that.value == true ? 1 : 0
                data.order_time = that.todayDate + " " + that.nowTime + ":00"
                data.receiver = that.current + 1
                console.log(data)
                if (that.query.source == 'add') {
                    addNewTiming(data).then((res) => {
                        that.show6 = false
                        if (res.code == 200) {
                            uni.showToast({
                                title: res.message
                            })
                            setTimeout(function() {
                                let pages = getCurrentPages();
                                let currPage = pages[pages.length - 1] //当前页面
                                let prePage = pages[pages.length - 3] //上一个页面
                                //调用上一页拉取数据的方法
                                prePage.$vm.getList()
                                uni.navigateBack({})
                            }, 1500)
                            uni.removeStorageSync("timing")
                        }else if(res.code == 4003){
                                that.show7 = true
                        }else {
                            uni.showToast({
                                title: res.message,
                                icon: "none"
                            })
                        }
                    })
                } else if (that.query.source == 'edit') {
                    data._method = "put"
                    editTiming(data, that.query.id).then((res) => {
                        console.log(res)
                        that.show6 = false
                        if (res.code == 200) {
                            uni.showToast({
                                title: res.message
                            })
                            setTimeout(function() {
                                let pages = getCurrentPages();
                                let currPage = pages[pages.length - 1] //当前页面
                                let prePage = pages[pages.length - 3] //上一个页面
                                console.log("prePage", pages)
                                //调用上一页拉取数据的方法
                                prePage.$vm.getList()
                                uni.navigateBack({})
                            }, 1500)
                            uni.removeStorageSync("timing")
                        }else if(res.code == 4003){
                                that.show7 = true
                        } else {
                            uni.showToast({
                                title: res.message,
                                icon: "none"
                            })
                        }
                    })
                }
            }
        }
    }
</script>

<style lang="scss">
    .container {
        border-top: 2upx solid #D2D2D7;
        box-sizing: border-box;
        padding-top: 24upx;

        .cons {
            text-align: center;
        }

        .can {
            width: 100%;
            height: 80upx;
            border-radius: 20upx;
            display: flex;
            align-items: center;
            // justify-content: space-between;
            border: 2upx solid #aaa;
            overflow: hidden;
            margin: 34upx 0 60upx;

            .canLeft {
                background: #EAEAEA;
                text-align: center;
                border-right: 2upx solid #aaa;
                height: 100%;
                line-height: 80upx;
                width: 80upx;
                box-sizing: border-box;
                padding-left: 8upx;
            }
        }

        .fu {
            font-size: 24upx;
            font-family: Hiragino Sans-W3, Hiragino Sans;
            font-weight: normal;
            color: rgba(29, 29, 31, 0.9);
        }

        .appointSet {
            display: flex;
            align-items: center;
            justify-content: space-between;
            margin-top: 43upx;
            border-bottom: 2upx solid #d2d2d7;
            padding-bottom: 30upx;
        }

        .blank {
            width: 100%;
            height: 50upx;
        }

        .btn {
            width: 478upx;
            height: 96upx;
            background: rgba(29, 29, 31, 0.1);
            border-radius: 20upx;
            opacity: 1;
            border: 2upx solid #707070;
            font-size: 32upx;
            font-family: Hiragino Sans-W3, Hiragino Sans;
            font-weight: normal;
            color: #707070;
            margin-top: 144upx;
        }

        .content {
            border-left: 2upx solid #D2D2D7;
            border-right: 2upx solid #D2D2D7;
            border-top: 2upx solid #D2D2D7;
            margin: 32upx 0 0;
        }

        .contentItem {
            display: flex;
            align-items: center;
            justify-content: space-between;
            box-sizing: border-box;
            padding: 32upx;
            border-bottom: 2upx solid #D2D2D7;

            .tabLeft {
                .tabTop {
                    font-size: 32upx;
                    font-family: Hiragino Sans-W3, Hiragino Sans;
                    font-weight: normal;
                    color: #1D1D1F;
                    margin-bottom: 20upx;
                }

                .tabBot {
                    font-size: 32upx;
                    font-family: Hiragino Sans-W3, Hiragino Sans;
                    font-weight: normal;
                    color: #AAAAAA;
                }
            }

            .tabRight {
                image {
                    height: 46upx;
                    width: 23upx;
                }
            }
        }


        .item {
            display: flex;
            align-items: center;
            margin-top: 60upx;

            .itemLeft {
                margin-right: 28upx;
            }

            .unselect {
                width: 40upx;
                height: 40upx;
                background: #FFFFFF;
                opacity: 1;
                box-sizing: border-box;
                border: 2upx solid #707070;
                border-radius: 50%;
            }

            .selected {
                width: 40upx;
                height: 40upx;
                background: #FFFFFF;
                border: 2upx solid #1A73E8;
                border-radius: 50%;
                box-sizing: border-box;
                padding: 6upx;

                .fill {
                    width: 100%;
                    height: 100%;
                    background: #1A73E8;
                    border-radius: 50%;
                }
            }

        }

        .mem1 {
            font-size: 28upx;
            font-family: Hiragino Sans-W3, Hiragino Sans;
            font-weight: normal;
            color: #707070;
            text-align: right;
            margin-bottom: 14upx;
        }

        .mem2 {
            font-size: 32upx;
            font-family: Hiragino Sans-W3, Hiragino Sans;
            font-weight: normal;
            color: #707070;
            text-align: right;

            text {
                color: #1D1D1F;
            }
        }

        .title {
            font-size: 32upx;
            font-family: Hiragino Sans-W3, Hiragino Sans;
            font-weight: normal;
            color: #1D1D1F;
            margin-top: 40upx;
            border-bottom: 2upx solid #d2d2d7;
            padding-bottom: 22upx;
        }
    }
</style>
